-- Migration 11 (compact): seed assessment item banks
begin;
update assessments set subtitle='The Exponential Level Assessment',category='church',scale_min=0,scale_max=3,estimated_minutes=15,questions_per_page=10,sensitivity='standard',is_published=true where slug='church-growth';
delete from items where assessment_id=(select id from assessments where slug='church-growth');
with a as (select id from assessments where slug='church-growth') insert into items (assessment_id,item_order,text,domain,is_scored,is_reverse_scored,item_type) select a.id,v.ord,v.txt,v.dom,v.sc,false,v.it::item_type from a,(values (1,'Our attendance is growing consistently year over year.','3',true,'standard'),(2,'Key leaders or families have left the church in the past year.','1',true,'standard'),(3,'We have a clear sending culture where leaders are released, not held back.','5',true,'standard'),(4,'Our church is financially stable but not investing in growth.','2',true,'standard'),(5,'Our church has launched or is actively planning a new campus or location.','4',true,'standard'),(6,'Our congregation feels discouraged or uncertain about the future.','1',true,'standard'),(7,'Guests visit regularly and many of them return and get connected.','3',true,'standard'),(8,'We talk about growth but rarely take steps to make it happen.','2',true,'standard'),(9,'Our church has sent out leaders or teams to plant new churches.','5',true,'standard'),(10,'Our leadership team thinks beyond our local church to regional impact.','4',true,'standard'),(11,'We have not seen salvations or baptisms recently.','1',true,'standard'),(12,'We are seeing regular salvations and baptisms.','3',true,'standard'),(13,'Our church has produced other churches that are now producing churches.','5',true,'standard'),(14,'Our church has the financial and organizational capacity to expand.','4',true,'standard'),(15,'Leadership is focused primarily on keeping the church together.','1',true,'standard'),(16,'Our pastor casts a clear and compelling vision for the future.','3',true,'standard'),(17,'We see occasional guests but struggle to retain them.','2',true,'standard'),(18,'We actively partner with other churches and networks to multiply ministry.','5',true,'standard'),(19,'Our vision includes reaching more people than our current location can hold.','4',true,'standard'),(20,'There is no clear vision being communicated by leadership.','1',true,'standard'),(21,'We have a defined discipleship pathway for new believers.','3',true,'standard'),(22,'Our ministries are running but few of them are expanding.','2',true,'standard'),(23,'We invest in training leaders with the expectation that some will lead new works.','4',true,'standard'),(24,'Our attendance has decreased over the past 12 months.','1',true,'standard'),(25,'Our leadership pipeline is designed to send leaders out, not just fill internal roles.','5',true,'standard'),(26,'We have a general sense of vision but it is not clearly defined or communicated.','2',true,'standard'),(27,'Our church invests consistently in outreach and community engagement.','3',true,'standard'),(28,'We are losing more members than we are gaining.','1',true,'standard'),(29,'We have a formal process for raising up and deploying leaders.','4',true,'standard'),(30,'Multiplication is a core value, not just a goal, in our church culture.','5',true,'standard'),(31,'Our congregation is comfortable but not highly motivated to grow.','2',true,'standard'),(32,'We are intentionally identifying and developing emerging leaders.','3',true,'standard'),(33,'We celebrate and support leaders who step into new assignments or locations.','4',true,'standard'),(34,'Our church struggles financially on a regular basis.','1',true,'standard'),(35,'Our congregation is growing in giving and financial generosity.','3',true,'standard'),(36,'Our pastor champions multiplication from the pulpit and in personal leadership.','5',true,'standard'),(37,'Leadership development happens informally, if at all.','2',true,'standard'),(38,'Our leadership team is unified and moving in the same direction.','3',true,'standard'),(39,'We have systems and structures in place that could be replicated in a new location.','4',true,'standard'),(40,'There is little to no outreach happening in our community.','1',true,'standard'),(41,'Our pastor spends most of their energy managing problems, not building vision.','1',true,'standard'),(42,'New ministries or groups are being launched to meet growing needs.','3',true,'standard'),(43,'We have a defined church planting or sending strategy, not just a general desire.','5',true,'standard'),(44,'We have some outreach activity but it is inconsistent.','2',true,'standard'),(45,'We partner with our denomination or network to support growth and expansion.','4',true,'standard'),(46,'Our attendance has stayed about the same for the past 1 to 3 years.','2',true,'standard'),(47,'Our leadership pipeline produces more leaders than we need for internal roles.','4',true,'standard'),(48,'We measure success not just by who comes but by who we send.','5',true,'standard'),(49,'Our church''s greatest contribution to the Kingdom is the churches and leaders we produce.','5',true,'standard'),(50,'Leadership is focused on maintaining programs and services.','2',true,'standard')) as v(ord,txt,dom,sc,it);
update assessments set subtitle='A Spiritual Maturity Assessment',category='personal',scale_min=1,scale_max=5,estimated_minutes=15,questions_per_page=20,sensitivity='standard',is_published=true where slug='rooted';
delete from items where assessment_id=(select id from assessments where slug='rooted');
with a as (select id from assessments where slug='rooted') insert into items (assessment_id,item_order,text,domain,is_scored,is_reverse_scored,item_type) select a.id,v.ord,v.txt,v.dom,v.sc,false,v.it::item_type from a,(values (1,'I stay spiritually connected to Christ throughout my normal day, not just in church settings.','Abiding in Christ',true,'standard'),(2,'When I feel distant from God, I notice it and take steps to reconnect.','Abiding in Christ',true,'standard'),(3,'My relationship with Jesus feels alive, not routine or empty.','Abiding in Christ',true,'standard'),(4,'I depend on Christ for my daily strength, not just my own effort.','Abiding in Christ',true,'standard'),(5,'I regularly sense God''s presence in ordinary moments, not only in worship services.','Abiding in Christ',true,'standard'),(6,'I read Scripture on a regular basis, not only when I''m preparing to teach or preach.','Word & Prayer',true,'standard'),(7,'My prayer life includes listening to God, not only asking Him for things.','Word & Prayer',true,'standard'),(8,'Scripture regularly shapes decisions I make, not just my beliefs.','Word & Prayer',true,'standard'),(9,'I have a consistent time set aside for prayer and the Word.','Word & Prayer',true,'standard'),(10,'When life gets busy, prayer and Scripture are among the first things I protect, not the first things I drop.','Word & Prayer',true,'standard'),(11,'People who know me well would say my character has grown over the last year.','Fruit of the Spirit',true,'standard'),(12,'I respond to conflict with patience more often than I used to.','Fruit of the Spirit',true,'standard'),(13,'I can name specific ways I have grown in love, joy, or peace recently.','Fruit of the Spirit',true,'standard'),(14,'Self-control shows up in my daily habits, not just my public behavior.','Fruit of the Spirit',true,'standard'),(15,'I am quicker to show kindness and gentleness than I was a year ago.','Fruit of the Spirit',true,'standard'),(16,'I have people in my life who know the real me, not just my public role.','Community & Accountability',true,'standard'),(17,'Someone has permission to ask me hard questions and expect an honest answer.','Community & Accountability',true,'standard'),(18,'I am currently in real community, not just attending church services.','Community & Accountability',true,'standard'),(19,'I have confessed a struggle to someone else in the last year.','Community & Accountability',true,'standard'),(20,'I would notice, and be bothered, if I drifted from accountability.','Community & Accountability',true,'standard'),(21,'I am actively using my gifts to serve others, not just aware of what they are.','Serving & Gifts',true,'standard'),(22,'Serving feels like an offering to God, not an obligation I''m fulfilling.','Serving & Gifts',true,'standard'),(23,'I look for ways to serve outside of my formal ministry role.','Serving & Gifts',true,'standard'),(24,'I have said yes to serving even when it wasn''t convenient.','Serving & Gifts',true,'standard'),(25,'I recognize the gifts in others and encourage them to use their gifts.','Serving & Gifts',true,'standard'),(26,'I have shared my faith with someone outside the church in the last year.','Witness & Mission',true,'standard'),(27,'I pray regularly for specific people who don''t know Christ.','Witness & Mission',true,'standard'),(28,'My life outside of church reflects the same faith I profess inside it.','Witness & Mission',true,'standard'),(29,'I look for natural opportunities to talk about what God is doing in my life.','Witness & Mission',true,'standard'),(30,'I care personally about people coming to know Christ, not just about church growth numbers.','Witness & Mission',true,'standard'),(31,'I give financially in a way that reflects trust in God, not just leftover margin.','Stewardship',true,'standard'),(32,'I manage my time in a way that honors God''s priorities, not just my own.','Stewardship',true,'standard'),(33,'I am a faithful steward of what God has given me, even when no one is watching.','Stewardship',true,'standard'),(34,'I make financial decisions with eternity in mind, not just comfort.','Stewardship',true,'standard'),(35,'I have said no to something I wanted so I could be faithful with what I already have.','Stewardship',true,'standard'),(36,'My faith has grown stronger through hard seasons, not just survived them.','Perseverance in Trials',true,'standard'),(37,'I keep trusting God even when I don''t understand what He''s doing.','Perseverance in Trials',true,'standard'),(38,'I have walked through a real trial in the last few years and can point to what it taught me.','Perseverance in Trials',true,'standard'),(39,'I don''t abandon spiritual practices just because life gets difficult.','Perseverance in Trials',true,'standard'),(40,'I have hope that endures even when circumstances don''t improve quickly.','Perseverance in Trials',true,'standard')) as v(ord,txt,dom,sc,it);
update assessments set subtitle='A Ministry Calling Assessment',category='personal',scale_min=0,scale_max=3,estimated_minutes=10,questions_per_page=25,sensitivity='standard',is_published=true where slug='fivefold-calling';
delete from items where assessment_id=(select id from assessments where slug='fivefold-calling');
with a as (select id from assessments where slug='fivefold-calling') insert into items (assessment_id,item_order,text,domain,is_scored,is_reverse_scored,item_type) select a.id,v.ord,v.txt,v.dom,v.sc,false,v.it::item_type from a,(values (1,'I am energized by starting new ministries or reaching new groups of people, rather than maintaining what already exists.','Pioneering (Apostolic)',true,'standard'),(2,'I naturally see opportunities others don''t see yet.','Pioneering (Apostolic)',true,'standard'),(3,'I am willing to leave comfort and stability to go where the need is greatest.','Pioneering (Apostolic)',true,'standard'),(4,'People often look to me to get a new initiative off the ground.','Pioneering (Apostolic)',true,'standard'),(5,'I would rather build something new than manage something already established.','Pioneering (Apostolic)',true,'standard'),(6,'I am quick to sense when something isn''t right, even if others haven''t noticed yet.','Prophetic',true,'standard'),(7,'I feel a strong pull toward truth and calling things what they actually are, even when it''s uncomfortable.','Prophetic',true,'standard'),(8,'I often sense direction from God that I feel compelled to share with others.','Prophetic',true,'standard'),(9,'I care more about being faithful to what''s right than being liked.','Prophetic',true,'standard'),(10,'People sometimes tell me I see things clearly before anyone else does.','Prophetic',true,'standard'),(11,'I look for natural opportunities to talk with people who don''t know Christ.','Evangelistic',true,'standard'),(12,'I get excited talking about my faith with someone who has never heard it.','Evangelistic',true,'standard'),(13,'I have led someone to Christ outside of a formal church setting.','Evangelistic',true,'standard'),(14,'I feel most alive when I''m sharing the gospel with someone new.','Evangelistic',true,'standard'),(15,'I can explain the gospel simply, in a way an outsider can understand.','Evangelistic',true,'standard'),(16,'I am drawn to caring for people through their struggles over the long haul.','Shepherding',true,'standard'),(17,'People come to me when they are hurting, and I make time for them.','Shepherding',true,'standard'),(18,'I notice when someone is missing or drifting, and I follow up.','Shepherding',true,'standard'),(19,'I find deep satisfaction in walking with the same people over years, not just seasons.','Shepherding',true,'standard'),(20,'Protecting and nurturing people matters more to me than moving fast.','Shepherding',true,'standard'),(21,'I enjoy studying Scripture deeply and explaining it clearly to others.','Teaching',true,'standard'),(22,'People tell me I help them understand things they didn''t understand before.','Teaching',true,'standard'),(23,'I prepare thoroughly before I teach or explain something important.','Teaching',true,'standard'),(24,'I care about accuracy and depth, not just making a point land emotionally.','Teaching',true,'standard'),(25,'I naturally break down complex ideas into steps others can follow.','Teaching',true,'standard')) as v(ord,txt,dom,sc,it);
update assessments set subtitle='An Adult Leadership Wiring Assessment',category='personal',scale_min=1,scale_max=5,estimated_minutes=10,questions_per_page=14,sensitivity='standard',is_published=true where slug='wired-to-lead';
delete from items where assessment_id=(select id from assessments where slug='wired-to-lead');
with a as (select id from assessments where slug='wired-to-lead') insert into items (assessment_id,item_order,text,domain,is_scored,is_reverse_scored,item_type) select a.id,v.ord,v.txt,v.dom,v.sc,false,v.it::item_type from a,(values (1,'I like being in charge and making the call.','D',true,'standard'),(2,'I make decisions quickly and move forward without dwelling.','D',true,'standard'),(3,'I welcome a challenge, especially one people doubt can be done.','D',true,'standard'),(4,'I get straight to the point instead of talking around an issue.','D',true,'standard'),(5,'I would rather lead an initiative than wait to be assigned one.','D',true,'standard'),(6,'I push hard to reach a goal, even when it''s uncomfortable for others.','D',true,'standard'),(7,'I am comfortable taking a calculated risk to get results.','D',true,'standard'),(8,'I build relationships easily and enjoy meeting new people.','I',true,'standard'),(9,'I bring energy to a room and lift the mood of a meeting.','I',true,'standard'),(10,'I can get people excited about a new idea or direction.','I',true,'standard'),(11,'I would rather talk something through with others than work it out alone.','I',true,'standard'),(12,'I stay hopeful and look for the upside, even in a hard season.','I',true,'standard'),(13,'I enjoy encouraging people publicly, not just privately.','I',true,'standard'),(14,'I use stories and illustrations naturally when I communicate.','I',true,'standard'),(15,'I stay calm when things get stressful or chaotic.','S',true,'standard'),(16,'I am loyal and stick with people and commitments for the long haul.','S',true,'standard'),(17,'People know they can depend on me to follow through.','S',true,'standard'),(18,'I would rather preserve peace than start a conflict, even when I probably should speak up.','S',true,'standard'),(19,'I prefer steady, predictable routines over constant change.','S',true,'standard'),(20,'I listen patiently before I respond, even under pressure.','S',true,'standard'),(21,'I am the person people come to when they need someone calm in the room.','S',true,'standard'),(22,'I want to understand all the facts before I make a decision.','C',true,'standard'),(23,'I catch details and inconsistencies that other people miss.','C',true,'standard'),(24,'I prefer doing something right over doing it fast.','C',true,'standard'),(25,'I follow a clear process rather than winging it.','C',true,'standard'),(26,'I hold myself and others to a high standard of accuracy.','C',true,'standard'),(27,'I would rather have a well-researched plan than a bold guess.','C',true,'standard'),(28,'I take time to think things through before I speak.','C',true,'standard')) as v(ord,txt,dom,sc,it);
update assessments set subtitle='A Marriage & Ministry Assessment',category='ministry',scale_min=1,scale_max=5,estimated_minutes=12,questions_per_page=20,sensitivity='sensitive',is_published=false where slug='called-together';
delete from items where assessment_id=(select id from assessments where slug='called-together');
with a as (select id from assessments where slug='called-together') insert into items (assessment_id,item_order,text,domain,is_scored,is_reverse_scored,item_type) select a.id,v.ord,v.txt,v.dom,v.sc,false,v.it::item_type from a,(values (1,'We both feel personally called to this ministry, not just one of us.','Shared Calling',true,'standard'),(2,'We regularly talk about where we sense God leading us next.','Shared Calling',true,'standard'),(3,'I believe my spouse fully supports the ministry work we do together.','Shared Calling',true,'standard'),(4,'We make major ministry decisions together, not alone.','Shared Calling',true,'standard'),(5,'I would choose this calling again if I could start over.','Shared Calling',true,'standard'),(6,'We protect at least one full day a week that ministry does not touch.','Boundaries: Home vs Ministry',true,'standard'),(7,'Our home has clear limits on when church needs can interrupt family time.','Boundaries: Home vs Ministry',true,'standard'),(8,'My spouse and I agree on how many nights a week ministry can take us away from home.','Boundaries: Home vs Ministry',true,'standard'),(9,'We turn off ministry calls and messages during family time.','Boundaries: Home vs Ministry',true,'standard'),(10,'Our vacations and days off are rarely interrupted by church needs.','Boundaries: Home vs Ministry',true,'standard'),(11,'I understand what the church expects of me as a ministry spouse.','Role & Expectations',true,'standard'),(12,'Those expectations were something we agreed to together, not something assumed of me.','Role & Expectations',true,'standard'),(13,'I feel free to say no to a ministry role I am not gifted or called for.','Role & Expectations',true,'standard'),(14,'My spouse defends me when the congregation''s expectations of me are unfair.','Role & Expectations',true,'standard'),(15,'We have talked honestly about which ministry tasks are mine to carry and which are not.','Role & Expectations',true,'standard'),(16,'We spend meaningful time together that has nothing to do with ministry.','Connection & Intimacy',true,'standard'),(17,'We pray for each other, not only for the ministry.','Connection & Intimacy',true,'standard'),(18,'Physical affection between us has not been crowded out by ministry demands.','Connection & Intimacy',true,'standard'),(19,'I know how my spouse is really doing, not just how they look from the outside.','Connection & Intimacy',true,'standard'),(20,'We still pursue each other the way we did earlier in our relationship.','Connection & Intimacy',true,'standard'),(21,'When we disagree, we can say so honestly, even about ministry decisions.','Conflict & Communication',true,'standard'),(22,'We resolve conflict privately before it ever becomes visible to the church.','Conflict & Communication',true,'standard'),(23,'I feel safe telling my spouse when something they did hurt me.','Conflict & Communication',true,'standard'),(24,'We do not let unresolved conflict linger for days without addressing it.','Conflict & Communication',true,'standard'),(25,'Being public figures does not stop us from having real conversations at home.','Conflict & Communication',true,'standard'),(26,'We keep a regular rhythm of rest that ministry does not override.','Margin, Rest & Finances',true,'standard'),(27,'Money stress from ministry income does not regularly strain our marriage.','Margin, Rest & Finances',true,'standard'),(28,'I recognize the signs when my spouse is running on empty.','Margin, Rest & Finances',true,'standard'),(29,'We have said no to ministry opportunities to protect our health.','Margin, Rest & Finances',true,'standard'),(30,'We have a plan, not just a hope, for our financial future.','Margin, Rest & Finances',true,'standard'),(31,'When someone criticizes my spouse''s ministry, it does not create distance between us.','Criticism & Resilience',true,'standard'),(32,'We process criticism together rather than letting one of us carry it alone.','Criticism & Resilience',true,'standard'),(33,'Public criticism of our ministry has not made us more guarded with each other.','Criticism & Resilience',true,'standard'),(34,'We remind each other that criticism does not define our worth.','Criticism & Resilience',true,'standard'),(35,'A hard season in ministry has not become a hard season in our marriage.','Criticism & Resilience',true,'standard'),(36,'We have someone outside our own church who speaks into our marriage.','Support & Community',true,'standard'),(37,'We have friends who know us apart from our ministry titles.','Support & Community',true,'standard'),(38,'We are willing to ask for help when our marriage needs it.','Support & Community',true,'standard'),(39,'We have a mentor couple or counselor we could call if things got hard.','Support & Community',true,'standard'),(40,'We do not carry the weight of ministry and marriage entirely alone.','Support & Community',true,'standard'),(41,'Do you feel physically or emotionally safe in your marriage right now?','Safety',false,'safety_check')) as v(ord,txt,dom,sc,it);
update assessments set subtitle='A Leadership Team Assessment',category='church',scale_min=1,scale_max=5,estimated_minutes=20,questions_per_page=20,sensitivity='standard',is_published=false where slug='church-health';
delete from items where assessment_id=(select id from assessments where slug='church-health');
with a as (select id from assessments where slug='church-health') insert into items (assessment_id,item_order,text,domain,is_scored,is_reverse_scored,item_type) select a.id,v.ord,v.txt,v.dom,v.sc,false,v.it::item_type from a,(values (1,'Our church is intentionally raising up new leaders, not just relying on the same few people.','Leadership Development',true,'standard'),(2,'Leaders here are trained and released, not just recruited to fill a gap.','Leadership Development',true,'standard'),(3,'I can name someone in our church who has grown into a leadership role in the last year.','Leadership Development',true,'standard'),(4,'Our pastor invests real time in developing other leaders, not just doing ministry himself.','Leadership Development',true,'standard'),(5,'We have a clear next step for someone who wants to grow into leadership here.','Leadership Development',true,'standard'),(6,'Most people in our church are actively serving somewhere, not just attending.','Every-Member Ministry',true,'standard'),(7,'New people are helped to discover their gifts and find a place to serve.','Every-Member Ministry',true,'standard'),(8,'Our church treats every member''s ministry as valuable, not just the platform roles.','Every-Member Ministry',true,'standard'),(9,'People are given real responsibility here, not just busywork.','Every-Member Ministry',true,'standard'),(10,'I know what my own gifts are and where they fit in this church.','Every-Member Ministry',true,'standard'),(11,'Prayer is a real, active part of how our church makes decisions, not a formality.','Prayer & Spiritual Depth',true,'standard'),(12,'Our people are growing in their personal walk with God, not just attending services.','Prayer & Spiritual Depth',true,'standard'),(13,'Our church regularly sets aside dedicated time for prayer, not just mentioning it from the platform.','Prayer & Spiritual Depth',true,'standard'),(14,'I sense real spiritual hunger in our congregation, not just routine.','Prayer & Spiritual Depth',true,'standard'),(15,'Our leadership models a genuine devotional life, not just a busy ministry schedule.','Prayer & Spiritual Depth',true,'standard'),(16,'People know where to go and who to ask when they have a question or a need.','Clear Systems & Communication',true,'standard'),(17,'Information flows clearly from leadership to the congregation, not just top-down announcements with no follow-through.','Clear Systems & Communication',true,'standard'),(18,'Our systems, like check-in, follow-up, and communication, actually work, not just exist on paper.','Clear Systems & Communication',true,'standard'),(19,'New people are followed up with quickly and consistently.','Clear Systems & Communication',true,'standard'),(20,'Our church''s structure helps ministry happen, rather than slowing it down.','Clear Systems & Communication',true,'standard'),(21,'Our worship services genuinely connect people with God, not just fill an hour.','Worship That Connects',true,'standard'),(22,'Guests and newcomers can follow and engage with our services without feeling lost.','Worship That Connects',true,'standard'),(23,'Our worship reflects excellence and preparation, not last-minute effort.','Worship That Connects',true,'standard'),(24,'People leave our services encouraged and changed, not just entertained.','Worship That Connects',true,'standard'),(25,'Our preaching is clear, biblical, and applicable to daily life.','Worship That Connects',true,'standard'),(26,'Most of our people are in some kind of ongoing relational group, not just Sunday attendance.','Groups & Discipleship',true,'standard'),(27,'Real discipleship, not just information, is happening in our groups.','Groups & Discipleship',true,'standard'),(28,'People in our groups know each other well enough to notice when someone is struggling.','Groups & Discipleship',true,'standard'),(29,'Our groups are actively multiplying or starting new ones, not staying static.','Groups & Discipleship',true,'standard'),(30,'New people are welcomed and assimilated into a group quickly.','Groups & Discipleship',true,'standard'),(31,'Our church regularly reaches people who don''t yet know Christ, not just transfers from other churches.','Outward Focus & Evangelism',true,'standard'),(32,'Our people are equipped and confident to share their faith outside of church walls.','Outward Focus & Evangelism',true,'standard'),(33,'Our church invests real resources, time, money, and people, into reaching our community.','Outward Focus & Evangelism',true,'standard'),(34,'We measure our success partly by who we''re reaching, not just who''s already here.','Outward Focus & Evangelism',true,'standard'),(35,'Outreach is something our whole church does, not just a designated team.','Outward Focus & Evangelism',true,'standard'),(36,'Conflict in our church gets addressed directly and biblically, not avoided or allowed to fester.','Unity & Relational Health',true,'standard'),(37,'Our leadership team is unified and trusts each other.','Unity & Relational Health',true,'standard'),(38,'People in our church genuinely love and care for one another, not just tolerate each other.','Unity & Relational Health',true,'standard'),(39,'Our church has healed well from past conflict or hurt, not just moved past it quietly.','Unity & Relational Health',true,'standard'),(40,'New people are welcomed warmly and quickly feel like they belong.','Unity & Relational Health',true,'standard')) as v(ord,txt,dom,sc,it);
update assessments set subtitle='A Self and Team Leadership Assessment',category='church',scale_min=1,scale_max=5,estimated_minutes=15,questions_per_page=20,sensitivity='standard',is_published=false where slug='leadership-health';
delete from items where assessment_id=(select id from assessments where slug='leadership-health');
with a as (select id from assessments where slug='leadership-health') insert into items (assessment_id,item_order,text,domain,is_scored,is_reverse_scored,item_type) select a.id,v.ord,v.txt,v.dom,v.sc,false,v.it::item_type from a,(values (1,'I have a clear sense of where I''m leading people, not just what needs to get done today.','Vision & Direction',true,'standard'),(2,'I communicate vision often enough that people around me could repeat it in their own words.','Vision & Direction',true,'standard'),(3,'I make time to think ahead, not just react to what''s urgent.','Vision & Direction',true,'standard'),(4,'People who follow me understand why we''re doing what we''re doing, not just what to do.','Vision & Direction',true,'standard'),(5,'I revisit and adjust our direction when circumstances change, rather than defaulting to the original plan out of habit.','Vision & Direction',true,'standard'),(6,'I make decisions in a reasonable amount of time, not paralyzed by indecision.','Decision-Making',true,'standard'),(7,'I gather the right input before deciding, without letting that become an excuse to delay.','Decision-Making',true,'standard'),(8,'I own the outcome of my decisions, good or bad, rather than shifting blame.','Decision-Making',true,'standard'),(9,'I am willing to make an unpopular decision when it''s the right one.','Decision-Making',true,'standard'),(10,'I don''t let fear of criticism keep me from deciding what needs to be decided.','Decision-Making',true,'standard'),(11,'People understand what I''m asking of them the first time I say it.','Communication',true,'standard'),(12,'I listen as much as I talk in conversations that matter.','Communication',true,'standard'),(13,'I communicate difficult things directly, not through hints or through someone else.','Communication',true,'standard'),(14,'I follow through on what I say I''ll communicate or follow up on.','Communication',true,'standard'),(15,'I adjust how I communicate depending on who I''m talking to, not just my own default style.','Communication',true,'standard'),(16,'I give real responsibility to others, not just tasks I don''t want to do myself.','Delegation & Team Building',true,'standard'),(17,'I trust the people I''ve delegated to, rather than micromanaging their work.','Delegation & Team Building',true,'standard'),(18,'I am actively developing someone who could eventually replace me in my role.','Delegation & Team Building',true,'standard'),(19,'My team feels ownership over their work, not just compliance with my instructions.','Delegation & Team Building',true,'standard'),(20,'I recognize and credit others'' contributions publicly, not just privately.','Delegation & Team Building',true,'standard'),(21,'I recover from setbacks in a reasonable amount of time, not carrying them for weeks.','Emotional & Spiritual Resilience',true,'standard'),(22,'My mood and energy are steady enough that people around me aren''t managing my emotions.','Emotional & Spiritual Resilience',true,'standard'),(23,'I have a consistent practice, spiritual or otherwise, that keeps me grounded under pressure.','Emotional & Spiritual Resilience',true,'standard'),(24,'I know the early warning signs when I''m running on empty, and I take them seriously.','Emotional & Spiritual Resilience',true,'standard'),(25,'I don''t take criticism of my leadership as an attack on my identity.','Emotional & Spiritual Resilience',true,'standard'),(26,'What I do in private matches what I say and teach in public.','Integrity & Accountability',true,'standard'),(27,'I have someone in my life who has permission to challenge my decisions.','Integrity & Accountability',true,'standard'),(28,'I admit when I''m wrong quickly, without needing to be cornered into it.','Integrity & Accountability',true,'standard'),(29,'I keep commitments even when it''s inconvenient or costly to do so.','Integrity & Accountability',true,'standard'),(30,'I am honest about my own weaknesses with the people closest to me, not just my strengths.','Integrity & Accountability',true,'standard'),(31,'I address tension directly instead of hoping it resolves on its own.','Conflict Navigation',true,'standard'),(32,'I can disagree with someone and still maintain the relationship afterward.','Conflict Navigation',true,'standard'),(33,'I stay calm enough in conflict to think clearly, not just react.','Conflict Navigation',true,'standard'),(34,'I follow up after a conflict to make sure it''s actually resolved, not just quieted.','Conflict Navigation',true,'standard'),(35,'I am willing to have the hard conversation instead of avoiding the person.','Conflict Navigation',true,'standard'),(36,'I am actively working on a specific weakness right now, not just aware that I have one.','Growth & Adaptability',true,'standard'),(37,'I seek out feedback rather than waiting for it to be offered.','Growth & Adaptability',true,'standard'),(38,'I have changed my mind about something significant in the last year based on new information.','Growth & Adaptability',true,'standard'),(39,'I invest time in my own growth, not just my ministry''s growth.','Growth & Adaptability',true,'standard'),(40,'I adapt my leadership approach as the situation or the people change, rather than leading the same way regardless of context.','Growth & Adaptability',true,'standard')) as v(ord,txt,dom,sc,it);
commit;